using System.Collections;
using System.Collections.Generic;
using TMPro;
using UnityEngine;
using UnityEngine.UI;

/// <summary>
/// Popup temporário de coleccionável (ex: "+1 Runa de Gaia"): overlay
/// (CanvasGroup, Screen Space - Overlay) que mostra brevemente o texto/ícone
/// de <c>PickupBase.popupText</c> ao ser recolhido, com fade in/out. Mensagens
/// recebidas enquanto outra está visível são colocadas numa fila e mostradas
/// em sequência (em vez de se sobreporem ou se perderem).
///
/// Singleton com auto-fallback (mesmo padrão de PlayerProgress/DeathScreenUI —
/// ver Tarefa #15/#16).
///
/// Montagem no Editor:
/// - Canvas (Screen Space - Overlay) com um "panelRoot" (painel pequeno, ex:
///   canto superior do HUD) + "canvasGroup" no mesmo GameObject.
/// - "messageText" (TMP_Text): texto do popup.
/// - "iconImage" (Image, opcional): ícone do coleccionável.
/// </summary>
public class PickupPopupUI : MonoBehaviour
{
    public static PickupPopupUI Instance { get; private set; }

    [Header("Painel")]
    [SerializeField] private GameObject panelRoot;
    [SerializeField] private CanvasGroup canvasGroup;
    [SerializeField] private TMP_Text messageText;
    [SerializeField] private Image iconImage;

    [Header("Transição")]
    [Tooltip("Duração do fade in/out, em segundos.")]
    [SerializeField] private float fadeDuration = 0.2f;

    [Tooltip("Tempo (s) com o popup totalmente visível, sem contar o fade.")]
    [SerializeField] private float holdDuration = 1.5f;

    private bool isAutoFallback;
    private bool isShowing;
    private readonly Queue<PopupRequest> _queue = new Queue<PopupRequest>();

    private struct PopupRequest
    {
        public string text;
        public Sprite icon;
    }

    private void Awake()
    {
        if (Instance != null && Instance != this)
        {
            if (Instance.isAutoFallback && !isAutoFallback)
            {
                Destroy(Instance.gameObject);
            }
            else
            {
                Destroy(gameObject);
                return;
            }
        }

        Instance = this;
        transform.SetParent(null);
        DontDestroyOnLoad(gameObject);

        if (canvasGroup != null) canvasGroup.alpha = 0f;
        if (panelRoot != null) panelRoot.SetActive(false);
    }

    [RuntimeInitializeOnLoadMethod(RuntimeInitializeLoadType.BeforeSceneLoad)]
    private static void EnsureExists()
    {
        if (Instance != null) return;
        var go = new GameObject(nameof(PickupPopupUI) + " (Fallback)");
        var instance = go.AddComponent<PickupPopupUI>();
        instance.isAutoFallback = true;
    }

    /// <summary>
    /// Mostra "text" (e opcionalmente "icon") num popup temporário. Se já
    /// houver um popup visível, esta mensagem é colocada na fila e mostrada
    /// a seguir.
    /// </summary>
    public void Show(string text, Sprite icon = null)
    {
        if (string.IsNullOrEmpty(text)) return;

        _queue.Enqueue(new PopupRequest { text = text, icon = icon });
        if (!isShowing) StartCoroutine(ShowQueueRoutine());
    }

    private IEnumerator ShowQueueRoutine()
    {
        isShowing = true;

        while (_queue.Count > 0)
        {
            var request = _queue.Dequeue();

            if (messageText != null) messageText.text = request.text;

            if (iconImage != null)
            {
                iconImage.sprite = request.icon;
                iconImage.gameObject.SetActive(request.icon != null);
            }

            // Sem UI montada (instância "Fallback" auto-criada sem montagem no
            // Editor) — apenas espera (mantém o espaçamento entre mensagens),
            // sem overlay.
            if (canvasGroup == null)
            {
                yield return WaitUnscaled(holdDuration);
                continue;
            }

            if (panelRoot != null) panelRoot.SetActive(true);

            yield return FadeRoutine(0f, 1f);
            yield return WaitUnscaled(holdDuration);
            yield return FadeRoutine(1f, 0f);

            if (panelRoot != null) panelRoot.SetActive(false);
        }

        isShowing = false;
    }

    private IEnumerator WaitUnscaled(float duration)
    {
        float t = 0f;
        while (t < duration)
        {
            t += Time.unscaledDeltaTime;
            yield return null;
        }
    }

    private IEnumerator FadeRoutine(float from, float to)
    {
        if (canvasGroup == null) yield break;

        canvasGroup.alpha = from;

        if (fadeDuration <= 0f)
        {
            canvasGroup.alpha = to;
            yield break;
        }

        float t = 0f;
        while (t < fadeDuration)
        {
            t += Time.unscaledDeltaTime;
            canvasGroup.alpha = Mathf.Lerp(from, to, t / fadeDuration);
            yield return null;
        }
        canvasGroup.alpha = to;
    }
}
